let strAge = "20";
let numericAge = Number(strAge);
console.log(numericAge + 5);

let a = "15";
let b = "10";
let sum = Number(a) + Number(b);
console.log(sum);

function multiplyInputs(val1, val2) {
  let result = Number(val1) * Number(val2);
  if (Number.isNaN(result)) {
    return 0;
  }
  return result;
}
